def get_user(user_id):
    user_id = request.args.get('id')
    query = f'SELECT * FROM users WHERE id = {user_id}'
    cursor.execute(query)
    return cursor.fetchone()

def get_user_safe(user_id):
    user_id = request.args.get('id')
    cursor.execute('SELECT * FROM users WHERE id = %s', (user_id,))
    return cursor.fetchone()

def search_products(request):
    term = request.form.get('q')
    query = 'SELECT * FROM products WHERE name LIKE \'' + term + '\''
    cursor.execute(query)
    return cursor.fetchall()

def run_lint(filepath):
    result = subprocess.run(['pylint', filepath], capture_output=True, text=True)
    return result.stdout

def read_file(request):
    filename = request.args.get('file')
    with open(f'/var/data/{filename}') as f:
        return f.read()

def read_report(request):
    filename = request.args.get('file')
    safe_name = os.path.basename(filename)
    with open(os.path.join('/var/reports', safe_name)) as f:
        return f.read()

def calculate(request):
    expr = request.args.get('expr')
    result = eval(expr)
    return str(result)

def load_defaults():
    defaults = eval("{'timeout': 30, 'retries': 3}")
    return defaults

def load_model(request):
    data = request.files['model'].read()
    model = pickle.loads(data)
    return model.predict([1, 2, 3])

def load_cache():
    with open('/var/cache/model.pkl', 'rb') as f:
        data = f.read()
    return pickle.loads(data)

def generate_report(report_id):
    report_id = int(report_id)
    cursor.execute('SELECT * FROM reports WHERE id = %s', (report_id,))
    return cursor.fetchall()

ALLOWED_TOOLS = {'ls', 'pwd', 'whoami'}

def run_tool(request):
    tool = request.args.get('tool')
    if tool not in ALLOWED_TOOLS:
        return 'forbidden', 403
    result = subprocess.run([tool], capture_output=True, text=True)
    return result.stdout

def filter_orders(request):
    status = request.args.get('status')
    orders = Order.objects.raw(f'SELECT * FROM orders WHERE status = "{status}"')
    return list(orders)

def login_redirect(request):
    next_url = request.args.get('next', '/')
    if current_user.is_authenticated:
        return redirect(next_url)

ALLOWED_HOSTS = {'example.com', 'app.example.com'}

def safe_redirect(request):
    next_url = request.args.get('next', '/')
    parsed = urlparse(next_url)
    if parsed.netloc and parsed.netloc not in ALLOWED_HOSTS:
        next_url = '/'
    return redirect(next_url)

def load_plugin(request):
    name = request.args.get('plugin')
    mod = __import__(name)
    return mod.run()

def update_profile_safe(request):
    data = request.json
    allowed = {k: data[k] for k in ('display_name', 'bio') if k in data}
    User.query.filter_by(id=current_user.id).update(allowed)
    db.session.commit()
